create table xxrmais_invoices (
    header_id               number not null enable,
    cliente_id              number not null enable,
    numero_nff              number not null enable,
    codigoverificacao       varchar2(400 byte),
    dataemissao             date not null enable,
    outrasinformacoes       varchar2(4000 byte),
    basecalculo             number,
    valorliquido            number,
    valorcredito            number,
    cnpj_cpf                varchar2(15 byte) not null enable,
    inscricaomunicipal_emit varchar2(15 byte),
    razaosocial_emit        varchar2(300 byte) not null enable,
    nomefantasia_emit       varchar2(300 byte),
    endereco_emit           varchar2(300 byte),
    numero_emit             number,
    bairro_emit             varchar2(300 byte),
    uf_emit                 varchar2(30 byte),
    cep_emit                varchar2(30 byte),
    telefone_emit           varchar2(40 byte),
    codigomunicipio_emit    varchar2(60 byte),
    municipio_emit          varchar2(60 byte),
    competencia             varchar2(60 byte),
    valorservicos           number,
    valordeducoes           number,
    valorpis                number,
    valorcofins             number,
    valorinss_servico       number,
    valorir                 number,
    valorcsll               number,
    vlrissretido            number,
    alqissreti              number,
    outrasretencoes         number,
    valoriss                number,
    descontoincondicio      number,
    descontocondicio        number,
    issretido               number,
    codigomunicipio_serv    varchar2(30 byte),
    inscricaomunicipal_dest varchar2(60 byte),
    cnpj_dest               varchar2(15 byte) not null enable,
    razaosocial_dest        varchar2(300 byte) not null enable,
    endereco_dest           varchar2(300 byte),
    numero_dest             number,
    uf_dest                 varchar2(30 byte),
    nomemunicipio_dest      varchar2(150 byte),
    telefone_dest           varchar2(30 byte),
    email_dest              varchar2(150 byte),
    codestabtomador         varchar2(40 byte),
    nomeestabtomador        varchar2(300 byte),
    optantesimplesnacio     varchar2(1 byte),
    incentivofiscal         varchar2(300 byte),
    serv_code               number,
    status                  varchar2(30 byte),
    creation_date           date,
    last_update             date,
    created_by              number,
    last_update_by          number,
    tipo_nf                 varchar2(10 byte) not null enable,
    adicional               clob,
    serie                   varchar2(10 byte),
    natop                   varchar2(50 byte),
    eletronic_invoice_key   number not null enable,
    pag_date                date
);


